mapper.select:
SELECT r.id AS refund_id, r.order_id, r.user_id, u.username, r.refund_no, r.refund_amount, r.refund_type, CASE r.refund_type WHEN 1 THEN '全额退款' WHEN 2 THEN '部分退款' ELSE '其他' END AS refund_type_label, r.refund_reason, r.refund_desc, r.proof_images, r.status, CASE r.status WHEN 0 THEN '待审核' WHEN 1 THEN '审核通过' WHEN 2 THEN '审核拒绝' WHEN 3 THEN '已取消' END AS status_label, r.audit_remark, r.audit_user_id, au.username AS audit_username, r.created_time, r.updated_time, r.audit_time, o.total_amount AS order_total_amount, o.status AS order_status, CASE o.status WHEN 0 THEN '待支付' WHEN 1 THEN '已支付' WHEN 2 THEN '已发货' WHEN 3 THEN '已完成' WHEN 4 THEN '已取消' END AS order_status_label FROM refund_order r LEFT JOIN `user` u ON r.user_id = u.id AND u.deleted = 0 LEFT JOIN `user` au ON r.audit_user_id = au.id AND au.deleted = 0 LEFT JOIN `order` o ON r.order_id = o.id
AND r.refund_no LIKE CONCAT('%', #{refundNo}, '%')
AND r.order_id = #{orderId}
AND u.username LIKE CONCAT('%', #{username}, '%')
AND r.status = #{status}
AND r.user_id = #{userId}
ORDER BY r.created_time DESC
